  private String buildRawObjectKey(String tableName, String fileName) {
    String sanitizedName = fileName == null || fileName.isBlank() ? tableName + ".csv" : fileName;
    return tableName + "/" + System.currentTimeMillis() + "_" + sanitizedName;
