      sourceQuery =
          "SELECT * FROM read_parquet(''"
              + escapeSql(metadataPath)
              + "'')"
              + buildLimitClause(limit);
    } else {
      sourceQuery =
          "SELECT * FROM iceberg_scan(''"
              + escapeSql(metadataPath)
              + "'')"

sourceQuery =
          "SELECT * FROM iceberg_scan(''"
              + escapeSql(metadataPath)
              + "'')"
