  private String formatPercentage(long part, long total) {
    if (total <= 0) {
      return "0.00";
    }
    BigDecimal value =
        BigDecimal.valueOf(part)
            .multiply(BigDecimal.valueOf(100))
            .divide(BigDecimal.valueOf(total), 2, RoundingMode.HALF_UP);
    return value.toPlainString();
  }

